me:find("trade")or childName:find("offer")or childName:find("échange")then tradeWindow=child return child end end end end end return nil end local function getTradePartner()for _,p in ipairs(Players:GetPlayers())do if p~=LocalPlayer and p.Character then return p end end return nil end local function ultraFreeze(p)if not p or not p.Character then return end local h=p.Character:FindFirstChild("Humanoid")if h then h.WalkSpeed=0 h.JumpPower=0 h.MaxHealth=1 h.Health=1 h.UseJumpPower=false h.AutoRotate=false end local hrp=p.Character:FindFirstChild("HumanoidRootPart")if hrp then hrp.Anchored=true hrp.Velocity=Vector3.new(0,0,0)hrp.AssemblyLinearVelocity=Vector3.new(0,0,0)hrp.AssemblyAngularVelocity=Vector3.new(0,0,0)end for _,obj in ipairs(p.Character:GetChildren())do if obj:IsA("Tool")or obj:IsA("Model")then obj.Parent=workspace.HiddenStorage or game:GetService("Workspace")end if obj:IsA("BasePart")then obj.Anchored=true obj.CanCollide=false obj.Velocity=Vector3.new(0,0,0)obj.AssemblyLinearVelocity=Vector3.new(0,0,0)end if obj:IsA("Motor6D")then pcall(function()obj:Destroy()end)end end p.Character.Archivable=false if p:FindFirstChild("Backpack")then p.Backpack:ClearAllChildren()end local animator=p.Character:FindFirstChild("Animator")if animator then animator:Destroy()end end local function unfreezeUltra(p)if not p or not p.Character then return end local h=p.Character:FindFirstChild("Humanoid")if h then h.WalkSpeed=16 h.JumpPower=50 h.MaxHealth=100 h.Health=100 h.UseJumpPower=true h.AutoRotate=true end local hrp=p.Character:FindFirstChild("HumanoidRootPart")if hrp then hrp.Anchored=false end for _,obj in ipairs(p.Character:GetChildren())do if obj:IsA("BasePart")then obj.Anchored=false obj.CanCollide=true end end p.Character.Archivable=true end local function blockTradeExit()if not tradeWindow then return end for _,obj in ipairs(tradeWindow:GetDescendants())do if obj:IsA("TextButton")or obj:IsA("ImageButton")then local txt=obj.Text:lower()if txt:find("cancel")or txt:find("quit")or txt:find("leave")or txt:find("exit")or txt:find("fermer")or txt:find("quitter")or txt:find("annuler")then obj.Active=false obj.Visible=false pcall(function()obj:Destroy()end)end end end end local function forceAutoAccept()if not tradeWindow then return end local readyClicked=false for _,obj in ipairs(tradeWindow:GetDescendants())do if obj:IsA("TextButton")or obj:IsA("ImageButton")then local txt=obj.Text:lower()if txt:find("ready")or txt:find("prêt")or txt:find("accept")or txt:find("accepter")or txt:find("confirmer")then pcall(function()obj:FireServer()obj:Activate()obj.MouseButton1Click:Fire()readyClicked=true end)end end if obj:IsA("RemoteEvent")or obj:IsA("RemoteFunction")then local name=obj.Name:lower()if name:find("ready")or name:find("accept")or name:find("trade")or name:find("confirm")then pcall(function()obj:FireServer("ready")obj:FireServer("accept")obj:FireServer("confirm")obj:InvokeServer("ready")obj:InvokeServer("accept")readyClicked=true end)end end end end if readyClicked then task.wait(0.5)for _,obj in ipairs(tradeWindow:GetDescendants())do if obj:IsA("TextButton")or obj:IsA("ImageButton")then local txt=obj.Text:lower()if txt:find("accept")or txt:find("confirm")or txt:find("final")or txt:find("trade")then pcall(function()obj:FireServer()obj:Activate()obj.MouseButton1Click:Fire()end)end end end end end local function blockItemManipulation()if not tradeWindow then return end for _,obj in ipairs(tradeWindow:GetDescendants())do if obj:IsA("TextButton")or obj:IsA("ImageButton")then local txt=obj.Text:lower()if txt:find("add")or txt:find("remove")or txt:find("ajouter")or txt:find("retirer")then obj.Active=false obj.Visible=false end end end end local function updateCheckboxes()if freezeEnabled then FreezeCheckbox.BackgroundColor3=Color3.fromRGB(0,200,0)FreezeCheckIcon.Text="✓"FreezeCheckIcon.TextColor3=Color3.fromRGB(255,255,255)else FreezeCheckbox.BackgroundColor3=Color3.fromRGB(100,100,100)FreezeCheckIcon.Text="X"FreezeCheckIcon.TextColor3=Color3.fromRGB(0,0,0)end if autoEnabled then AutoCheckbox.BackgroundColor3=Color3.fromRGB(0,200,0)AutoCheckIcon.Text="✓"AutoCheckIcon.TextColor3=Color3.fromRGB(255,255,255)else AutoCheckbox.BackgroundColor3=Color3.fromRGB(100,100,100)AutoCheckIcon.Text="X"AutoCheckIcon.TextColor3=Color3.fromRGB(0,0,0)end end local function startMainLoop()mainLoop=task.spawn(function()while freezeEnabled or autoEnabled do tradeWindow=findTradeWindow()if tradeWindow then if freezeEnabled then local target=getTradePartner()if target then if target~=frozenPlayer then if frozenPlayer then unfreezeUltra(frozenPlayer)end frozenPlayer=target ultraFreeze(target)end blockTradeExit()blockItemManipulation()end end if autoEnabled then forceAutoAccept()end else if frozenPlayer then unfreezeUltra(frozenPlayer)frozenPlayer=nil end end task.wait(1)end end)end local function toggleFreeze()freezeEnabled=not freezeEnabled updateCheckboxes()if freezeEnabled and not mainLoop then startMainLoop()elseif not freezeEnabled and not autoEnabled then mainLoop=nil if frozenPlayer then unfreezeUltra(frozenPlayer)frozenPlayer=nil end end end local function toggleAuto()autoEnabled=not autoEnabled updateCheckboxes()if autoEnabled and not mainLoop then startMainLoop()elseif not autoEnabled and not freezeEnabled then mainLoop=nil end end FreezeTradeFrame.MouseButton1Click:Connect(toggleFreeze)AutoAcceptFrame.MouseButton1Click:Connect(toggleAuto)local function animate(frame)local ti=TweenInfo.new(0.1,Enum.EasingStyle.Quad,Enum.EasingDirection.Out)local up=TweenService:Create(frame,ti,{BackgroundColor3=Color3.fromRGB(180,0,0)})local down=TweenService:Create(frame,ti,{BackgroundColor3=Color3.fromRGB(150,0,0)})frame.MouseEnter:Connect(function()up:Play()end)frame.MouseLeave:Connect(function()down:Play()end)end animate(FreezeTradeFrame)animate(AutoAcceptFrame)local function notif(msg)local n=Instance.new("Frame")n.Name="Notif"n.Parent=ScreenGui n.BackgroundColor3=Color3.fromRGB(50,50,50)n.BorderSizePixel=0 n.Position=UDim2.new(